// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

contract Betting {
    using SafeMath for uint256;

    // VRF variables
    bytes32 internal keyHash;
    uint256 internal fee;
    uint256 public randomResult;

    // Define the bet structure
    struct Bet {
        address bettor;
        uint256 amount;
        uint256 eventId;
        uint256 odds;
        uint256 outcome;
        BetStatus status;
    }

    // Define the event structure
    struct Event {
        string description;
        uint256 startTime;
        uint256[] outcomes;
        EventStatus status;
    }

    // Enums for bet and event status
    enum BetStatus { Pending, Ongoing, Completed }
    enum EventStatus { Pending, Ongoing, Completed }

    // Storage variables for bets and events
    mapping(uint256 => Bet) public bets;
    mapping(uint256 => Event) public events;
    uint256 public betCount;
    uint256 public eventCount;

    // Constructor
    constructor() {}

    // Functions for managing bets
    function placeBet(uint256 _eventId, uint256 _amount, uint256 _odds, uint256 _outcome) external {}
    function recordBetDetails(uint256 _betId) internal {}
    function updateBetStatus(uint256 _betId, BetStatus _newStatus) external {}
    function payoutWinnings(uint256 _betId) external {}

    // Functions for managing events
    function createEvent(string memory _description, uint256 _startTime, uint256[] memory _outcomes) external {}
    function updateEventStatus(uint256 _eventId, EventStatus _newStatus) external {}

    // Function for generating a random number (using a secure RNG contract) check ./CommitReveal.sol
    function getRandomNumber() internal returns (uint256) {}
}

contracts/CommitReveal.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

contract CommitReveal {
    mapping(address => bytes32) private commitments;
    mapping(address => uint256) private revealed;

    function commit(bytes32 hashedNumber) public {
        require(commitments[msg.sender] == 0, "You have already committed a number.");
        commitments[msg.sender] = hashedNumber;
    }

    function reveal(uint256 number, bytes32 secret) public {
        bytes32 hashedNumber = keccak256(abi.encodePacked(number, secret));
        require(commitments[msg.sender] == hashedNumber, "Invalid number or secret.");

        revealed[msg.sender] = number;
        commitments[msg.sender] = 0;
    }

    function generateRandomNumber() public view returns (uint256) {
        uint256 random = uint256(keccak256(abi.encodePacked(block.timestamp, block.prevrandao, revealed[msg.sender])));
        return random;
    }

    // Hashed number is coming from the frontend
    // ! Look into prevrandao to generate random numbers
    // refs: 
    /*
        https://ethereum.stackexchange.com/questions/137839/using-block-prevrandao-as-randomness-for-miller-rabin-primality-test
        https://ethereum.stackexchange.com/questions/137575/randomness-in-proof-of-stake
        https://eth2book.info/bellatrix/part2/building_blocks/randomness/
        https://soliditydeveloper.com/prevrandao
        https://twitter.com/0x_Beans/status/1570115095212208129
        https://www.youtube.com/watch?v=W3hgX4wVwoo&ab_channel=Soft.Tomatoes
    */
}

